package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreHeaderCase() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat updated = original.withIgnoreHeaderCase(true);

        assertNotNull(updated);
        assertTrue(updated.getIgnoreHeaderCase());
        assertNotSame(original, updated);

        // Also check that original is not changed
        assertFalse(original.getIgnoreHeaderCase());
    }
}
